-- V3: Seed 200+ flashcards across Java, AWS, System Design, DSA
-- ============================================================

INSERT INTO flashcards (id, topic, sub_topic, question, answer, difficulty_hint) VALUES

-- ── CORE JAVA ────────────────────────────────────────────────
(UUID(), 'Java', 'OOP', 'What are the four pillars of OOP?', 'Encapsulation (hiding state with getters/setters), Abstraction (hiding complexity via interfaces/abstract classes), Inheritance (extending behaviour), Polymorphism (method overriding and overloading allowing the same interface to behave differently).', 'EASY'),
(UUID(), 'Java', 'OOP', 'What is the difference between abstract class and interface?', 'Abstract class: can have state, constructors, concrete methods; single inheritance. Interface: no state (default/static methods only in Java 8+), multiple inheritance; use interface for "can-do" behaviour, abstract class for "is-a" with shared base implementation.', 'MEDIUM'),
(UUID(), 'Java', 'OOP', 'Explain method overloading vs method overriding.', 'Overloading: same method name, different parameters — resolved at compile time (static polymorphism). Overriding: subclass redefines superclass method with same signature — resolved at runtime (dynamic dispatch). @Override annotation catches errors at compile time.', 'EASY'),
(UUID(), 'Java', 'Memory', 'What is the JVM memory model? Explain heap vs stack.', 'Stack: per-thread, stores frames (local vars, references, return address), auto-managed LIFO. Heap: shared across threads, stores all objects; divided into Young Gen (Eden, S0, S1) and Old Gen. MetaSpace: class metadata. Minor GC is fast (Young); Full GC is slow (Old), causes stop-the-world pauses.', 'MEDIUM'),
(UUID(), 'Java', 'Memory', 'How does Garbage Collection work in Java? What is G1GC?', 'GC identifies unreachable objects and reclaims memory. Generational hypothesis: most objects die young. Minor GC: Eden → Survivor (S0/S1) → Old Gen. G1GC (Java 9+ default): divides heap into equal-sized regions, collects regions with most garbage first. Reduces worst-case pause times vs CMS.', 'HARD'),
(UUID(), 'Java', 'String', 'Why is String immutable in Java? What are the benefits?', 'String is final class; char[] is private final. Benefits: (1) Thread safety — no synchronisation needed. (2) String pool — literals can be safely shared. (3) Safe as HashMap key — hashCode stays consistent. (4) Security — prevents manipulation after validation (URLs, file paths).', 'MEDIUM'),
(UUID(), 'Java', 'String', 'What is the String constant pool and how does intern() work?', 'String literals are cached in the String pool (part of MetaSpace in Java 8+). Two literals with same value share one object. s.intern() checks pool, returns existing object if found or adds and returns. new String("abc") always creates heap object; new String("abc").intern() returns pool object.', 'MEDIUM'),
(UUID(), 'Java', 'Collections', 'Explain HashMap internals and how collisions are handled.', 'HashMap uses array of Node<K,V> buckets. Index = (n-1) & hash(key). Collision: chained as linked list. Java 8+: if bucket size > 8, converts to Red-Black Tree (O(log n)). Resizing: when size > capacity * loadFactor (default 0.75), array doubles and all entries rehashed. ConcurrentHashMap segments buckets for thread safety.', 'HARD'),
(UUID(), 'Java', 'Collections', 'What is the difference between ArrayList and LinkedList?', 'ArrayList: dynamic array, O(1) random access, O(n) insertion/deletion mid-list, good cache locality. LinkedList: doubly-linked list, O(n) access, O(1) insertion/deletion at known node, higher memory (two pointers per node). Choose ArrayList unless heavy insertions at beginning.', 'EASY'),
(UUID(), 'Java', 'Collections', 'What is the difference between HashMap, LinkedHashMap, and TreeMap?', 'HashMap: O(1) average ops, no ordering. LinkedHashMap: insertion-order (or access-order with accessOrder=true in constructor) — good for LRU cache. TreeMap: sorted by key (Red-Black Tree), O(log n) ops, implements NavigableMap with floor/ceiling/subMap.', 'MEDIUM'),
(UUID(), 'Java', 'Collections', 'What is the difference between HashSet and TreeSet?', 'HashSet: backed by HashMap, O(1) add/contains/remove, no ordering, allows null. TreeSet: backed by TreeMap, O(log n), sorted order, implements NavigableSet. Use HashSet for fast lookup, TreeSet when sorted order matters.', 'EASY'),
(UUID(), 'Java', 'Concurrency', 'What is the difference between synchronized keyword and ReentrantLock?', 'synchronized: implicit lock, auto-releases on exception, no tryLock. ReentrantLock: explicit lock/unlock, tryLock(timeout) prevents deadlock, can be interruptible, supports multiple conditions. Use ReentrantLock when you need timeout, interruptibility, or fairness policy.', 'MEDIUM'),
(UUID(), 'Java', 'Concurrency', 'What is a deadlock? How do you prevent it in Java?', 'Deadlock: Thread A holds lock X waiting for Y; Thread B holds Y waiting for X. Prevention: (1) Lock ordering — always acquire in same order. (2) tryLock(timeout) on ReentrantLock. (3) Avoid nested locks. (4) Use lock-free structures: ConcurrentHashMap, AtomicLong. (5) Use java.util.concurrent higher-level abstractions.', 'HARD'),
(UUID(), 'Java', 'Concurrency', 'Explain volatile keyword. When is it sufficient?', 'volatile guarantees visibility (reads/writes go directly to main memory, not CPU cache) and prevents instruction reordering for that variable. Sufficient when: one writer, multiple readers (e.g., a stop flag). NOT sufficient for compound operations like i++ (read-modify-write) — use AtomicInteger or synchronized.', 'MEDIUM'),
(UUID(), 'Java', 'Concurrency', 'What is the difference between Callable and Runnable?', 'Runnable: run() returns void, cannot throw checked exceptions. Callable<T>: call() returns T, can throw checked exceptions. Use Callable with ExecutorService.submit() which returns Future<T> for retrieving the result.', 'EASY'),
(UUID(), 'Java', 'Concurrency', 'How does CompletableFuture differ from Future?', 'Future.get() is blocking. CompletableFuture supports non-blocking composition: thenApply() (transform), thenCompose() (chain async), thenCombine() (merge two), exceptionally() (error handling), allOf() (wait all). Always supply a custom executor to avoid ForkJoinPool.commonPool() thread starvation in web contexts.', 'HARD'),
(UUID(), 'Java', 'Java8+', 'What are the main features introduced in Java 8?', 'Lambda expressions, Functional interfaces (Function, Predicate, Consumer, Supplier), Stream API (declarative data processing), Optional<T>, Default/static methods in interfaces, java.time API (LocalDate, Instant), Method references (Class::method), CompletableFuture improvements.', 'EASY'),
(UUID(), 'Java', 'Java8+', 'Explain Stream API — intermediate vs terminal operations.', 'Intermediate (lazy, return Stream): filter(), map(), flatMap(), sorted(), distinct(), limit(), peek(). Terminal (eager, trigger pipeline): collect(), forEach(), count(), reduce(), findFirst(), anyMatch(), toList(). Streams are single-use — create new stream for each pipeline.', 'MEDIUM'),
(UUID(), 'Java', 'Java8+', 'What is Optional and what are common anti-patterns?', 'Optional wraps a possibly-absent value. Use: as return type for optional results; with map/flatMap/filter/orElseGet. Anti-patterns: Optional in method parameters (use overloads), Optional as fields (serialisation issues), Optional in collections, calling get() without isPresent() check, orElse(expensiveCall()) — always evaluates, use orElseGet(() -> expensiveCall()).', 'MEDIUM'),
(UUID(), 'Java', 'Java8+', 'How do Functional Interfaces work? What is @FunctionalInterface?', '@FunctionalInterface marks an interface with exactly one abstract method (SAM — Single Abstract Method). Allows lambda syntax. Built-in: Function<T,R> (T→R), Predicate<T> (T→boolean), Consumer<T> (T→void), Supplier<T> (→T), BiFunction<T,U,R>. Compose with andThen(), compose(), negate().', 'MEDIUM'),
(UUID(), 'Java', 'Generics', 'What is type erasure in Java generics?', 'At compile time, generics are type-checked; at runtime, type parameters are erased and replaced with Object (or bound). This allows backward compatibility with pre-generics code. Consequence: cannot do new T[], instanceof T, or get Class<T> at runtime. Overcome with Class<T> token passed to constructor.', 'HARD'),
(UUID(), 'Java', 'Generics', 'What is the difference between <? extends T> and <? super T>?', 'Producer Extends, Consumer Super (PECS). <? extends T>: read-safe, write-restricted (cannot add, can read as T). Use as source. <? super T>: write-safe, read as Object (can add T, cannot read as T). Use as sink. Example: copy(List<? extends T> src, List<? super T> dest).', 'HARD'),
(UUID(), 'Java', 'Exceptions', 'What is the difference between checked and unchecked exceptions?', 'Checked (Exception subclass, not RuntimeException): must be declared in throws or caught at compile time. Unchecked (RuntimeException, Error): not required to declare/catch. Rule of thumb: checked for recoverable conditions (IOException, SQLException), unchecked for programming errors (NullPointerException, IllegalArgumentException).', 'EASY'),
(UUID(), 'Java', 'Exceptions', 'What happens to the return value of try when finally throws an exception?', 'The finally block always runs. If finally throws an exception, it replaces any exception or return value from try/catch — the original is lost. In Java 7+ try-with-resources, suppressed exceptions are attached to the main exception via addSuppressed().', 'HARD'),

-- ── SPRING BOOT ──────────────────────────────────────────────
(UUID(), 'Spring Boot', 'Core', 'Explain Inversion of Control (IoC) and Dependency Injection (DI).', 'IoC: the Spring container manages object lifecycle — your code does not call new(). DI is the mechanism: Spring injects dependencies into beans. Types: Constructor injection (preferred — immutable, testable), Setter injection (optional deps), Field @Autowired (avoid — hides deps). Beans managed by ApplicationContext, scoped as Singleton by default.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'Core', 'What is the Spring Bean lifecycle?', 'Instantiation → Dependency Injection → @PostConstruct / afterPropertiesSet() → Bean ready (serving requests) → @PreDestroy / destroy() → Garbage collected. ApplicationContext manages entire lifecycle. BeanPostProcessor hooks allow modification before/after initialisation.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'Core', 'What are the Spring bean scopes?', 'Singleton (default): one instance per ApplicationContext — must be thread-safe. Prototype: new instance per injection. Request: one per HTTP request (web). Session: one per HTTP session (web). Application: one per ServletContext. Use @Scope annotation or declare in config.', 'EASY'),
(UUID(), 'Spring Boot', 'Security', 'Explain how Spring Security JWT authentication works end-to-end.', 'Client POSTs credentials → AuthController → UserDetailsService.loadUserByUsername() → AuthenticationManager.authenticate() → generate JWT (HMAC-SHA256 signed). Client sends JWT in Authorization: Bearer header. JwtAuthFilter (OncePerRequestFilter): extract → validate → load UserDetails → set SecurityContextHolder. Subsequent requests use SecurityContext for authorisation.', 'HARD'),
(UUID(), 'Spring Boot', 'Security', 'What is the difference between @PreAuthorize and @Secured?', '@Secured: simple role-based ("ROLE_ADMIN"); does not support SpEL. @PreAuthorize: SpEL expressions; more powerful — @PreAuthorize("hasRole(''ADMIN'') and #id == authentication.principal.id"). Enable with @EnableMethodSecurity. @PostAuthorize evaluates after method returns.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'JPA', 'What is the N+1 problem in JPA and how do you fix it?', 'Fetching N entities then issuing N additional queries for each lazy-loaded association = N+1 total. Fix: JOIN FETCH in JPQL ("SELECT o FROM Order o JOIN FETCH o.customer"), @EntityGraph on repository method, @BatchSize(size=25) for batch loading, or DTO projections with @Query to skip entity graph entirely.', 'HARD'),
(UUID(), 'Spring Boot', 'JPA', 'Explain @Transactional propagation types with examples.', 'REQUIRED (default): join existing tx or create new. REQUIRES_NEW: always new tx, suspends outer — use for audit logging (must persist even if outer rolls back). NESTED: savepoint within outer tx. SUPPORTS: use if exists, otherwise non-transactional. NOT_SUPPORTED: always non-transactional. MANDATORY: must exist. NEVER: must not exist.', 'HARD'),
(UUID(), 'Spring Boot', 'JPA', 'What is the difference between @OneToMany EAGER vs LAZY fetch?', 'EAGER: loads association immediately with parent query (extra JOIN or subquery). LAZY: loads on first access (creates proxy). LAZY is always preferred — EAGER causes N+1 and loads unnecessary data. Use JOIN FETCH or @EntityGraph when you need the association for a specific query.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'REST', 'What is the difference between @Controller and @RestController?', '@Controller: MVC controller, returns view name by default. @RestController: @Controller + @ResponseBody — all methods return serialised response body (JSON/XML), no view resolution. @ResponseBody can be added to individual methods in @Controller for mixed behaviour.', 'EASY'),
(UUID(), 'Spring Boot', 'REST', 'How do you handle global exceptions in Spring Boot?', '@ControllerAdvice + @ExceptionHandler methods: intercept exceptions thrown by any controller. Annotate class with @RestControllerAdvice (= @ControllerAdvice + @ResponseBody). Map exception types to HTTP status codes with @ResponseStatus or ResponseEntity. Order multiple @ControllerAdvice with @Order.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'Config', 'What is the difference between @Value and @ConfigurationProperties?', '@Value("${prop}"): inject single property, supports SpEL, validated lazily. @ConfigurationProperties(prefix="app"): bind entire group of related properties to a typed Java class, supports validation with @Validated, IDE autocompletion, hierarchical config. Prefer @ConfigurationProperties for groups.', 'MEDIUM'),
(UUID(), 'Spring Boot', 'Config', 'How does Spring Boot auto-configuration work?', 'Spring Boot scans META-INF/spring/org.springframework.boot.autoconfigure.AutoConfiguration.imports (or spring.factories pre-2.7). Each listed class is conditionally applied based on @ConditionalOnClass, @ConditionalOnMissingBean, @ConditionalOnProperty etc. You override auto-config by declaring your own bean.', 'HARD'),
(UUID(), 'Spring Boot', 'Patterns', 'What is the difference between @Component, @Service, @Repository?', 'All are @Component specialisations. @Repository: marks data access layer, translates JPA/JDBC exceptions to Spring DataAccessException. @Service: business logic layer, no extra behaviour currently but documents intent. @Controller/@RestController: web layer. Use the specific annotations — @Repository exception translation is the only functional difference.', 'EASY'),

-- ── AWS ──────────────────────────────────────────────────────
(UUID(), 'AWS', 'Compute', 'What is the difference between EC2, Lambda, and ECS/EKS?', 'EC2: VMs; you manage OS, patching, scaling. Full control, always-running cost. Lambda: serverless functions; AWS manages everything, scales to 0, pay-per-invocation. Good for event-driven, stateless, <15min tasks. ECS/EKS: container orchestration; more control than Lambda, less than EC2. Fargate: serverless containers (no EC2 management).', 'MEDIUM'),
(UUID(), 'AWS', 'Compute', 'What is an EC2 Auto Scaling Group (ASG)?', 'ASG maintains a desired number of EC2 instances. Scaling policies: Target Tracking (maintain metric, e.g. CPU=60%), Step (add X instances when CPU>70%), Scheduled (pre-scale before events), Predictive (ML-based). Launch Template defines instance config. Min/max/desired capacity. Integrates with ALB target groups for automatic registration.', 'MEDIUM'),
(UUID(), 'AWS', 'Compute', 'What causes Lambda cold starts and how do you mitigate?', 'Cold start: Lambda must provision new execution environment (download code, start runtime, run init code). JVM cold start: 1-4 seconds. Mitigations: Provisioned Concurrency (pre-warm N instances, costs money), Lambda SnapStart for Java (restore from JVM snapshot ~1s), smaller packages (GraalVM native image), Go/Node have <200ms cold starts.', 'HARD'),
(UUID(), 'AWS', 'Storage', 'What are the S3 storage classes and when to use each?', 'Standard: frequent access, low latency. Intelligent-Tiering: auto-moves objects between tiers based on access patterns. Standard-IA: infrequent access, lower cost, retrieval fee. One Zone-IA: same but one AZ. Glacier Instant Retrieval: archive, ms retrieval. Glacier Flexible: minutes to hours. Glacier Deep Archive: 12h retrieval, cheapest. Use Lifecycle policies to auto-transition.', 'MEDIUM'),
(UUID(), 'AWS', 'Database', 'What is the difference between RDS Multi-AZ and Read Replicas?', 'Multi-AZ: synchronous standby in different AZ for HA and failover (1-2 min automatic failover). Standby cannot serve reads. Read Replicas: asynchronous copies for read scalability. Can serve SELECT queries. Up to 5 per primary. Can be promoted manually. Multi-AZ = HA, Read Replicas = Performance. Finance: Multi-AZ mandatory, Read Replicas for analytics.', 'MEDIUM'),
(UUID(), 'AWS', 'Database', 'How do you design DynamoDB partition keys to avoid hot partitions?', 'Hot partition: one PK gets disproportionate traffic (max 10GB, 3000 RCU, 1000 WCU per partition). Prevention: choose high-cardinality PK (userId, UUID); avoid status, date, category as sole PK. Write sharding: append random suffix (userId#0 through userId#9), scatter-gather on reads. Time-series: compound PK (deviceId + yyyy-mm) to spread across partitions.', 'HARD'),
(UUID(), 'AWS', 'Networking', 'Explain VPC subnets — public vs private, security layers.', 'Public subnet: has route to Internet Gateway, resources can communicate with internet (need public IP/EIP). Private subnet: no IGW route, use for DBs and internal services. NAT Gateway in public subnet for private resources to initiate outbound calls. Security Groups: stateful, instance-level firewall. NACLs: stateless, subnet-level. Finance: DBs always in private subnets, never publicly accessible.', 'MEDIUM'),
(UUID(), 'AWS', 'Messaging', 'What is the difference between SQS and SNS? Explain the fan-out pattern.', 'SQS: queue, point-to-point, message persists until consumer deletes, consumer pulls. SNS: topic, pub/sub, one message to all subscribers simultaneously, no persistence. Fan-out: SNS topic → multiple SQS queues (each subscriber gets durable queue, processes at its own rate). Use FIFO SQS for ordered payment processing, SNS for broadcasting fraud alerts to multiple systems.', 'MEDIUM'),
(UUID(), 'AWS', 'Security', 'What is IAM and explain the principle of least privilege?', 'IAM: Identity and Access Management controls who can do what to which AWS resource. Least privilege: grant only minimum permissions needed. Use IAM Roles for services/EC2/Lambda (never hardcode credentials). STS AssumeRole for cross-account. Permission Boundaries cap max permissions. SCPs for account-level. Finance: mandatory MFA, CloudTrail audit all calls, quarterly access review.', 'MEDIUM'),
(UUID(), 'AWS', 'Security', 'What is KMS and how does envelope encryption work?', 'KMS: AWS Key Management Service manages cryptographic keys. CMK (Customer Master Key) never leaves KMS in plaintext. Envelope encryption: generate Data Key (DK) from CMK, encrypt data with DK, encrypt DK with CMK, store encrypted DK with data. To decrypt: call KMS to decrypt DK, then decrypt data locally. Limits API calls and cost vs encrypting everything with CMK directly.', 'HARD'),
(UUID(), 'AWS', 'Architecture', 'What are the 6 pillars of the AWS Well-Architected Framework?', 'Operational Excellence (run and monitor), Security (protect data and systems), Reliability (recover from failures), Performance Efficiency (use resources efficiently), Cost Optimisation (avoid unnecessary costs), Sustainability (minimise environmental impact). Each has design principles and best practices.', 'EASY'),
(UUID(), 'AWS', 'Cost', 'What are the main EC2 pricing models and when to use each?', 'On-Demand: pay by hour/second, no commitment. Full price. Reserved (1-3yr): 40-60% savings for stable baseline. Savings Plans: flexible RI; commit to $ spend/hour, applies to EC2/Fargate/Lambda. Spot: 60-90% off, can be interrupted with 2-min notice — for fault-tolerant batch, ML training. Dedicated Hosts: compliance requirements (bring your own license).', 'MEDIUM'),
(UUID(), 'AWS', 'Observability', 'What is CloudWatch and how do you set up an alert for high error rates?', 'CloudWatch collects metrics, logs, events. Alarm: on a metric (e.g., Lambda Errors) → notify SNS → trigger Lambda or send email. Log Insights: query log groups with SQL-like syntax. Metric Filters: extract metrics from log patterns. Container Insights: ECS/EKS metrics. X-Ray: distributed tracing. CloudTrail: API audit log (different from CloudWatch).', 'MEDIUM'),

-- ── SYSTEM DESIGN ────────────────────────────────────────────
(UUID(), 'System Design', 'Fundamentals', 'Explain CAP Theorem. Which do you choose for financial systems?', 'Distributed systems can guarantee at most 2 of: Consistency (all nodes see same data), Availability (every request gets response), Partition Tolerance (survives network split). Network partitions always occur → choose CP or AP. Financial systems choose CP: cannot show stale balances, cannot double-charge. Sacrifice availability (show error) over inconsistency (show wrong balance).', 'HARD'),
(UUID(), 'System Design', 'Fundamentals', 'Explain horizontal vs vertical scaling. Which do you default to?', 'Vertical: bigger machine (more CPU/RAM). Simpler but has limits and creates SPOF. Horizontal: more machines behind load balancer. Complex (requires stateless design, distributed state management) but nearly unlimited scale. Default to horizontal — design services stateless from day one. Vertical is a temporary band-aid.', 'EASY'),
(UUID(), 'System Design', 'Fundamentals', 'What does it mean for a service to be stateless? Why does it matter?', 'Stateless: any server can handle any request — all context is in the request or external store (Redis/DB). Enables trivial horizontal scaling (add servers with no session stickiness). Stateful: server remembers client context — creates affinity, harder to scale/failover. Design: store session in Redis, not in-process memory.', 'MEDIUM'),
(UUID(), 'System Design', 'Fundamentals', 'What is idempotency and why is it critical for payment APIs?', 'Idempotent: calling the same operation multiple times produces the same result. Critical for retries — network failures can cause duplicate requests. Implementation: client sends unique idempotency-key (UUID) in request header. Server: check if key exists in DB/Redis → if yes, return stored result; if no, process and store. Prevents duplicate charges in payment APIs.', 'HARD'),
(UUID(), 'System Design', 'Caching', 'What are the main cache eviction policies? When to use each?', 'LRU (Least Recently Used): evict oldest-accessed item. Good for temporal locality (recently used likely needed again). LFU (Least Frequently Used): evict least-used item. Good for long-term hotspot caching. FIFO: simple, no tracking overhead. Random: unpredictable. Redis default: LRU with several variants (allkeys-lru, volatile-lru, allkeys-lfu).', 'MEDIUM'),
(UUID(), 'System Design', 'Caching', 'Explain cache-aside, write-through, and write-back caching strategies.', 'Cache-aside (lazy loading): app checks cache → on miss, load from DB, write to cache. Simple, cache only what''s needed. Write-through: write to cache AND DB simultaneously. Consistent but adds write latency. Write-back (write-behind): write to cache, async flush to DB. Fast writes, risk of data loss on cache failure. Finance: cache-aside for reads, write-through for consistency-critical data.', 'HARD'),
(UUID(), 'System Design', 'Databases', 'When would you choose SQL vs NoSQL?', 'SQL: ACID transactions, complex JOINs, structured schema, strong consistency. Choose for: financial records, inventory, user accounts. NoSQL: horizontal scale, flexible schema, eventual consistency. Choose for: user activity logs, session storage, product catalogs, time-series data. Often use both: SQL for transactional data + DynamoDB for event logs.', 'MEDIUM'),
(UUID(), 'System Design', 'Databases', 'What is database sharding and what are the challenges?', 'Sharding: partition data horizontally across multiple DB servers. Strategies: Range (by user ID range), Hash (hash(userId) mod n), Directory (lookup table maps key to shard). Challenges: cross-shard JOIN is expensive, resharding when adding nodes disrupts data (consistent hashing mitigates), hot shards if key distribution skewed, transactions across shards require distributed 2PC.', 'HARD'),
(UUID(), 'System Design', 'Databases', 'Explain database replication — master-slave and multi-master.', 'Master-slave (primary-replica): all writes to primary, async replicated to replicas for reads. Simple but replica lag can cause stale reads. Multi-master: multiple nodes accept writes — requires conflict resolution (last-write-wins or CRDTs). Use master-slave for read-heavy workloads. Multi-master for geo-distributed writes (Cassandra, DynamoDB multi-region).', 'HARD'),
(UUID(), 'System Design', 'Messaging', 'Kafka vs RabbitMQ — when to use each?', 'Kafka: distributed log, messages retained after consumption (replay), ordered within partition, high throughput (millions/sec), consumer groups. Use for: event streaming, audit logs, analytics pipelines, event sourcing. RabbitMQ: traditional message broker, messages deleted after ACK, supports routing, exchanges, fanout. Use for: task queues, RPC, work distribution. Kafka = event streaming, RabbitMQ = task queuing.', 'HARD'),
(UUID(), 'System Design', 'Patterns', 'What is the Circuit Breaker pattern? How does it work?', 'Prevents cascading failures when downstream service is failing. States: Closed (normal) → Open (failure threshold exceeded, fail-fast without calling downstream) → Half-Open (periodic probe to check recovery). Implemented with Resilience4j in Spring Boot. Configure failure rate threshold, wait duration, ring buffer size. Finance: circuit breaker on external payment gateway calls.', 'MEDIUM'),
(UUID(), 'System Design', 'Patterns', 'Explain the Saga pattern for distributed transactions.', 'Saga: sequence of local transactions, each publishing events. Two types: Choreography (services react to events directly, no central coordinator, decoupled but hard to debug) and Orchestration (central Saga Orchestrator calls each service in order, easier to trace). Compensating transactions undo completed steps on failure. Use when you need ACID across microservices.', 'HARD'),
(UUID(), 'System Design', 'Patterns', 'What is back pressure and how do you implement it?', 'Back pressure: consumer signals to producer to slow down when overwhelmed. Prevents unbounded queue growth and OOM. Implementations: bounded queues (reject when full), reactive streams with Project Reactor (Flux with limitRate()), Kafka consumer lag monitoring + producer throttling, rate limiting endpoints, HTTP 429 responses. Design principle: make failure visible, don''t silently buffer forever.', 'HARD'),
(UUID(), 'System Design', 'Rate Limiting', 'Explain Token Bucket and Sliding Window rate limiting algorithms.', 'Token Bucket: bucket holds N tokens, refilled at rate R/sec. Each request consumes 1 token. Allows bursting up to bucket capacity. Leaky Bucket: requests leak out at constant rate — smooths bursts. Fixed Window: count in time window, resets at boundary (burst at edge). Sliding Window Log: exact but high memory. Sliding Window Counter: approximate, lightweight. Token Bucket is most common for APIs.', 'HARD'),
(UUID(), 'System Design', 'Load Balancing', 'What load balancing algorithms exist and when to use each?', 'Round Robin: even distribution, simple. Weighted Round Robin: allocate more to powerful servers. Least Connections: send to server with fewest active connections — good for variable request durations. IP Hash / Consistent Hashing: same client always hits same server (session affinity). Random: simple but uneven. Consistent hashing best for cache servers and database routing to minimise remapping on scale.', 'MEDIUM'),
(UUID(), 'System Design', 'Architecture', 'Microservices vs Monolith — when to choose each?', 'Monolith: simple to develop/deploy/debug, single DB, shared memory. Good for small teams and early stages. Microservices: independent deployability, isolated failures, polyglot, but: network calls, distributed tracing, complex deployments, data consistency challenges. Conway''s Law: architecture mirrors team structure. Start monolith, extract services when you feel pain (different scaling needs, team ownership boundaries, deployment coupling).', 'MEDIUM'),
(UUID(), 'System Design', 'Consistency', 'What are the different consistency models in distributed systems?', 'Strong consistency: all reads reflect latest write (requires coordination, slow). Eventual consistency: all nodes converge to same value eventually (fast, available). Read-your-writes: you always see your own writes. Monotonic reads: never see older data after seeing newer. Causal consistency: related operations seen in causal order. Finance: strong for balances, eventual for analytics, read-your-writes for profile updates.', 'HARD'),

-- ── DSA CONCEPTS ─────────────────────────────────────────────
(UUID(), 'DSA', 'Complexity', 'What is Big O notation? Explain O(1), O(log n), O(n), O(n log n), O(n²).', 'Big O describes worst-case growth rate. O(1): constant time (HashMap lookup). O(log n): halving search space (binary search). O(n): single pass (linear scan). O(n log n): divide and conquer (merge sort, heap sort). O(n²): nested loops (bubble sort). O(2^n): exponential (brute force subsets). O(n!): factorial (all permutations). Aim for O(n) or O(n log n) in interviews.', 'EASY'),
(UUID(), 'DSA', 'Sorting', 'Explain merge sort — time complexity and when to use it.', 'Merge sort: divide array in half, recursively sort each half, merge. O(n log n) worst case (guaranteed), O(n) space. Stable sort (equal elements preserve original order). Use when: stability required, sorting linked lists (no random access), external sorting (data too large for memory — merge sorted chunks from disk). Java Arrays.sort for objects uses TimSort (merge sort variant).', 'MEDIUM'),
(UUID(), 'DSA', 'Sorting', 'Explain quick sort — time complexity, pivot selection, worst case.', 'Quick sort: pick pivot, partition into < pivot and > pivot, recursively sort. O(n log n) average, O(n²) worst case (already sorted with first-element pivot). In-place O(log n) space. Mitigation: random pivot selection or median-of-three. Not stable. Faster in practice than merge sort (better cache behaviour). Java Arrays.sort for primitives uses dual-pivot quicksort.', 'MEDIUM'),
(UUID(), 'DSA', 'Trees', 'What is the difference between BFS and DFS? When to use each?', 'BFS: level-by-level using a queue. Use when: shortest path in unweighted graph, level-order traversal, finding nearest node. DFS: depth-first using recursion or stack. Use when: path existence, cycle detection, topological sort, connected components, backtracking problems. BFS memory: O(width of tree). DFS memory: O(height). BFS preferred for shortest path, DFS for exhaustive exploration.', 'MEDIUM'),
(UUID(), 'DSA', 'Trees', 'Explain Red-Black Tree properties. Where does Java use it?', 'Self-balancing BST with 5 properties: (1) Every node is Red or Black. (2) Root is Black. (3) Null leaves are Black. (4) Red nodes have Black children. (5) All paths from node to null have equal Black nodes. Guarantees O(log n) operations. Java uses it in: TreeMap, TreeSet, HashMap buckets (when bucket size > 8 in Java 8+), and ConcurrentHashMap.', 'HARD'),
(UUID(), 'DSA', 'Graphs', 'What is Dijkstra''s algorithm and when does it fail?', 'Dijkstra finds shortest path from source to all nodes in weighted graph. Uses min-heap/priority queue. O((V+E) log V). Greedy: always processes closest unvisited node. Fails with negative edge weights (use Bellman-Ford instead). Cannot detect negative cycles. Works for both directed and undirected graphs with non-negative weights.', 'HARD'),
(UUID(), 'DSA', 'Graphs', 'What is Union-Find (Disjoint Set Union)?', 'DSU: tracks connected components. Operations: find(x) returns root of x''s component, union(x,y) merges components. Optimisations: Path Compression (make every node point directly to root during find) and Union by Rank/Size (always attach smaller tree to larger). Both optimisations together give nearly O(1) amortised per operation. Use for: cycle detection, Kruskal''s MST, network connectivity.', 'HARD'),
(UUID(), 'DSA', 'DP', 'What is dynamic programming? When to use memoization vs tabulation?', 'DP: optimise problems with overlapping subproblems and optimal substructure by storing results. Memoization (top-down): recursive + cache, only computes needed subproblems, more intuitive. Tabulation (bottom-up): iterative table, no recursion overhead, solves all subproblems. Use memoization when not all subproblems need solving; tabulation when all subproblems needed and space must be optimised.', 'MEDIUM'),
(UUID(), 'DSA', 'DP', 'What are the key DP problem patterns to recognise?', '1D DP: Fibonacci, house robber, climb stairs (current depends on previous 1-2). 2D DP: LCS, edit distance, knapsack (current cell from neighbours). Interval DP: matrix chain multiplication (consider all intervals). Tree DP: path sum, LCA. String DP: palindrome partitioning, word break. Bitmask DP: TSP, cover problems. Pattern: "minimum/maximum/count ways" often indicates DP.', 'HARD'),
(UUID(), 'DSA', 'Patterns', 'Explain the Two Pointers pattern. What problems does it solve?', 'Two pointers: use two indices to traverse array/string, typically from both ends or both from start. Reduces O(n²) brute force to O(n). Use when: array is sorted, or you need pairs/triplets summing to target, or removing duplicates. Examples: 2Sum (sorted), 3Sum, Valid Palindrome, Container with Most Water, Remove Duplicates from Sorted Array, Trapping Rain Water.', 'MEDIUM'),
(UUID(), 'DSA', 'Patterns', 'Explain the Sliding Window pattern. Fixed vs variable window.', 'Sliding window: move a window of elements across array/string without reprocessing. Fixed window: size K constant — Max sum subarray of size K. Variable window: expand right until condition met, shrink left to minimize — Minimum Window Substring, Longest Substring Without Repeating Characters. Template: right pointer expands, left pointer shrinks. O(n) total (each element added/removed at most once).', 'MEDIUM'),
(UUID(), 'DSA', 'Patterns', 'When do you use a Monotonic Stack?', 'Monotonic stack: maintains elements in monotonically increasing or decreasing order. Use when: "next greater element", "previous smaller element", calculating areas (Largest Rectangle in Histogram), Daily Temperatures. Pattern: for each element, pop from stack while condition violated, process popped elements, push current. O(n) since each element pushed/popped at most once.', 'HARD');
